module binary_decoder(
	input [1:0] invalid_binary,
	output [3:0] one_hot_out
);

	assign one_hot_out = (invalid_binary == 2'b00) ? 4'b0001 :
						 (invalid_binary == 2'b01) ? 4'b0010 :
						 (invalid_binary == 2'b10) ? 4'b0100 :
						 (invalid_binary == 2'b11) ? 4'b1000 : 4'b0000;

endmodule
